#include<bits/stdc++.h>
using namespace std;
#define int long long

int H(int n, int k)
{
	int res = n * k;
    int l = 1, r;
    while(l <= n)
    {
        if(k / l != 0)
            r = min(k / (k / l), n);
        else r = n;
        res-= (k / l) * (r - l + 1)* (l + r) / 2ll;
        l = r + 1;
    }
    return res;
}

signed main()
{
    int n, k;
	cin >> n >> k; 
    cout << H(n, k) << endl;
	return 0;
}
